class CertificatePinner {
  /// Creates an HttpClient with certificate pinning enabled for production hosts.
  static HttpClient createPinnedHttpClient() {
    final securityContext = SecurityContext.defaultContext;
    final httpClient = HttpClient(context: securityContext);

    httpClient.badCertificateCallback =
        (X509Certificate cert, String host, int port) {
      // Never accept bad certificates for production hosts
      if (host == ApiConfig.productionHost) {
        return false;
      }
      // Reject bad certificates for all hosts in production
      return false;
    };

    return httpClient;
  }

  /// Validates the certificate's public key against pinned hashes.
  /// This should be called after the TLS handshake to provide an additional
  /// layer of pinning validation.
  static bool validateCertificatePin(X509Certificate certificate) {
    try {
      final derBytes = certificate.der;
      final hash = sha256.convert(derBytes);
      final pinHash = 'sha256/${base64.encode(hash.bytes)}';

      return ApiConfig.certificatePins.contains(pinHash);
    } catch (e) {
      return false;
    }
  }
}

