// lib/services/auth_service.dart
import '../core/api_client.dart';
import '../core/api_exception.dart';
import '../core/secure_storage_service.dart';
import '../models/auth_result.dart';
import '../models/user_profile.dart';

class AuthService {
  final ApiClient _apiClient;
  final SecureStorageService _secureStorage;

  AuthService({
    required ApiClient apiClient,
    SecureStorageService? secureStorage,
  })  : _apiClient = apiClient,
        _secureStorage = secureStorage ?? SecureStorageService();

  Future<AuthResult> login({
    required String email,
    required String password,
  }) async {
    final response = await _apiClient.request(
      method: HttpMethod.post,
      path: '/auth/login',
      body: {
        'email': email,
        'password': password,
      },
      requiresAuth: false,
    );

    final authResult = AuthResult.fromJson(response);

    await _secureStorage.saveAccessToken(authResult.accessToken);
    await _secureStorage.saveRefreshToken(authResult.refreshToken);
    await _secureStorage.saveTokenExpiry(authResult.expiresAt);

    return authResult;
  }

  Future<AuthResult> register({
    required String email,
    required String password,
    required String displayName,
  }) async {
    final response = await _apiClient.request(
      method: HttpMethod.post,
      path: '/auth/register',
      body: {
        'email': email,
        'password': password,
        'display_name': displayName,
      },
      requiresAuth: false,
    );

    final authResult = AuthResult.fromJson(response);

    await _secureStorage.saveAccessToken(authResult.accessToken);
    await _secureStorage.saveRefreshToken(authResult.refreshToken);
    await _secureStorage.saveTokenExpiry(authResult.expiresAt);

    return authResult;
  }

  Future<void> logout() async {
    try {
      await _apiClient.request(
        method: HttpMethod.post,
        path: '/auth/logout',
      );
    } catch (_) {
      // Best effort - clear local tokens regardless
    } finally {
      await _secureStorage.clearAll();
    }
  }

  Future<bool> isAuthenticated() async {
    final token = await _secureStorage.getAccessToken();
    if (token == null) return false;

    final isExpired = await _secureStorage.isTokenExpired();
    if (!isExpired) return true;

    // Try to refresh
    final refreshToken = await _secureStorage.getRefreshToken();
    return refreshToken != null;
  }

  Future<void> requestPasswordReset({required String email}) async {
    await _apiClient.request(
      method: HttpMethod.post,
      path: '/auth/password-reset',
      body: {'email': email},
      requiresAuth: false,
    );
  }

  Future<void> changePassword({
    required String currentPassword,
    required String newPassword,
  }) async {
    await _apiClient.request(
      method: HttpMethod.post,
      path: '/auth/change-password',
      body: {
        'current_password': currentPassword,
        'new_password': newPassword,
      },
    );
  }
}

