import '../models/sync_result.dart';
import '../models/sync_item.dart';

enum ConflictResolution { clientWins, serverWins, manual }

class SyncService {
  final ApiClient _apiClient;
  DateTime? _lastSyncTime;
  bool _isSyncing = false;

  SyncService({required ApiClient apiClient}) : _apiClient = apiClient;

  bool get isSyncing => _isSyncing;
  DateTime? get lastSyncTime => _lastSyncTime;

  /// Performs a full bidirectional sync.
  /// Pushes local changes and pulls remote changes.
  Future<SyncResult> sync({
    required List<SyncItem> localChanges,
    ConflictResolution conflictResolution = ConflictResolution.serverWins,
  }) async {
    if (_isSyncing) {
      throw StateError('Sync already in progress');
    }

    _isSyncing = true;

    try {
      final response = await _apiClient.request(
        method: HttpMethod.post,
        path: '/sync',
        body: {
          'last_sync_at': _lastSyncTime?.toIso8601String(),
          'changes': localChanges.map((item) => item.toJson()).toList(),
          'conflict_resolution': conflictResolution.name,
        },
      );

      final result = SyncResult.fromJson(response);

      if (result.success) {
        _lastSyncTime = result.syncedAt;
      }

      return result;
    } finally {
      _isSyncing = false;
    }
  }

  /// Pulls only remote changes since last sync.
  Future<List<SyncItem>> pullChanges({
    String? itemType,
    int? limit,
    int? offset,
  }) async {
    final queryParams = <String, String>{};
    if (_lastSyncTime != null) {
      queryParams['since'] = _lastSyncTime!.toIso8601String();
    }
    if (itemType != null) queryParams['type'] = itemType;
    if (limit != null) queryParams['limit'] = limit.toString();
    if (offset != null) queryParams['offset'] = offset.toString();

    final response = await _apiClient.request(
      method: HttpMethod.get,
      path: '/sync/changes',
      queryParameters: queryParams,
    );

    final items = (response['data'] as List<dynamic>)
        .map((item) => SyncItem.fromJson(item as Map<String, dynamic>))
        .toList();

    if (response['synced_at'] != null) {
      _lastSyncTime = DateTime.parse(response['synced_at'] as String);
    }

    return items;
  }

  /// Pushes local changes to the server.
  Future<SyncResult> pushChanges({
    required List<SyncItem> changes,
  }) async {
    if (changes.isEmpty) {
      return SyncResult(
        syncedAt: DateTime.now(),
        itemsPushed: 0,
        itemsPulled: 0,
        conflicts: [],
        success: true,
      );
    }

    // Push in batches to avoid large payloads
    const batchSize = 50;
    int totalPushed = 0;
    final allConflicts = <SyncConflict>[];

    for (var i = 0; i < changes.length; i += batchSize) {
      final batch = changes.skip(i).take(batchSize).toList();

      final response = await _apiClient.request(
        method: HttpMethod.post,
        path: '/sync/push',
        body: {
          'changes': batch.map((item) => item.toJson()).toList(),
        },
      );

      final batchResult = SyncResult.fromJson(response);
      totalPushed += batchResult.itemsPushed;
      allConflicts.addAll(batchResult.conflicts);
    }

    final now = DateTime.now();
    _lastSyncTime = now;

    return SyncResult(
      syncedAt: now,
      itemsPushed: totalPushed,
      itemsPulled: 0,
      conflicts: allConflicts,
      success: allConflicts.isEmpty,
    );
  }

  /// Gets the sync status from the server.
  Future<Map<String, dynamic>> getSyncStatus() async {
    final response = await _apiClient.request(
      method: HttpMethod.get,
      path: '/sync/status',
    );

    return response;
  }

  /// Resolves a specific sync conflict.
  Future<void> resolveConflict({
    required String conflictId,
    required ConflictResolution resolution,
    Map<String, dynamic>? mergedData,
  }) async {
    await _apiClient.request(
      method: HttpMethod.post,
      path: '/sync/conflicts/$conflictId/resolve',
      body: {
        'resolution': resolution.name,
        if (mergedData != null) 'merged_data': mergedData,
      },
    );
  }

  void resetSyncState() {
    _lastSyncTime = null;
    _isSyncing = false;
  }
}

// lib/services/service_locator.dart
import '../core/api_client.dart';
import '../core/secure_storage_service.dart';
import 'auth_service.dart';
import 'profile_service.dart';
import 'sync_service.dart';

class ServiceLocator {
  static final ServiceLocator _instance = ServiceLocator._internal();
  factory ServiceLocator() => _instance;
  ServiceLocator._internal();

  late final SecureStorageService _secureStorage;
  late final ApiClient _apiClient;
  late final AuthService _authService;
  late final ProfileService _profileService;
  late final SyncService _syncService;

  bool _initialized = false;

  void initialize() {
    if (_initialized) return;

    _secureStorage = SecureStorageService();
    _apiClient = ApiClient(secureStorage: _secureStorage);
    _authService = AuthService(
      apiClient: _apiClient,
      secureStorage: _secureStorage,
    );
    _profileService = ProfileService(apiClient: _apiClient);
    _syncService = SyncService(apiClient: _apiClient);

    _initialized = true;
  }

  SecureStorageService get secureStorage => _secureStorage;
  ApiClient get apiClient => _apiClient;
  AuthService get authService => _authService;
  ProfileService get profileService => _profileService;
  SyncService get syncService => _syncService;

  void dispose() {
    _apiClient.dispose();
    _initialized = false;
  }
}

// lib/main.dart
import 'package:flutter/material.dart';
import 'services/service_locator.dart';
import 'core/api_exception.dart';
import 'models/user_profile.dart';
import 'models/sync_item.dart';
import 'models/sync_result.dart';

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  ServiceLocator().initialize();
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'API Client Demo',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.blue),
        useMaterial3: true,
      ),
      home: const HomeScreen(),
    );
  }
}

class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  final _services = ServiceLocator();
  UserProfile? _profile;
  bool _isLoading = false;
  bool _isAuthenticated = false;
  String? _statusMessage;
  SyncResult? _lastSyncResult;

  final _emailController = TextEditingController();
  final _passwordController = TextEditingController();

  @override
  void initState() {
    super.initState();
    _checkAuth();
  }

  @override
  void dispose() {
    _emailController.dispose();
    _passwordController.dispose();
    super.dispose();
  }

  Future<void> _checkAuth() async {
    final isAuth = await _services.authService.isAuthenticated();
    setState(() => _isAuthenticated = isAuth);
    if (isAuth) {
      await _loadProfile();
    }
  }

  Future<void> _login() async {
    if (_emailController.text.isEmpty || _passwordController.text.isEmpty) {
      _showMessage('Please enter email and password');
      return;
    }

    setState(() => _isLoading = true);

    try {
      final result = await _services.authService.login(
        email: _emailController.text.trim(),
        password: _passwordController.text,
      );

      setState(() {
        _isAuthenticated = true;
        _profile = result.user;
        _statusMessage = 'Logged in successfully';
      });
    } on CertificatePinningException {
      _showMessage(
          'Security error: Connection could not be verified. Please ensure you are on a trusted network.');
    } on ApiException catch (e) {
      _showMessage('Login failed: ${e.message}');
    } on NetworkException catch (e) {
      _showMessage('Network error: ${e.message}');
    } catch (e) {
      _showMessage('Unexpected error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _register() async {
    if (_emailController.text.isEmpty || _passwordController.text.isEmpty) {
      _showMessage('Please enter email and password');
      return;
    }

    setState(() => _isLoading = true);

    try {
      final result = await _services.authService.register(
        email: _emailController.text.trim(),
        password: _passwordController.text,
        displayName: _emailController.text.split('@').first,
      );

      setState(() {
        _isAuthenticated = true;
        _profile = result.user;
        _statusMessage = 'Registered successfully';
      });
    } on CertificatePinningException {
      _showMessage('Security error: Connection could not be verified.');
    } on ApiException catch (e) {
      _showMessage('Registration failed: ${e.message}');
    } catch (e) {
      _showMessage('Unexpected error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _logout() async {
    setState(() => _isLoading = true);

    try {
      await _services.authService.logout();
      _services.syncService.resetSyncState();

      setState(() {
        _isAuthenticated = false;
        _profile = null;
        _lastSyncResult = null;
        _statusMessage = 'Logged out';
      });
    } catch (e) {
      _showMessage('Logout error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _loadProfile() async {
    setState(() => _isLoading = true);

    try {
      final profile = await _services.profileService.getProfile();
      setState(() {
        _profile = profile;
        _statusMessage = 'Profile loaded';
      });
    } on AuthenticationException {
      setState(() {
        _isAuthenticated = false;
        _profile = null;
      });
      _showMessage('Session expired. Please log in again.');
    } on CertificatePinningException {
      _showMessage('Security error: Connection could not be verified.');
    } on ApiException catch (e) {
      _showMessage('Failed to load profile: ${e.message}');
    } catch (e) {
      _showMessage('Error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _updateProfile() async {
    setState(() => _isLoading = true);

    try {
      final updatedProfile = await _services.profileService.updateProfile(
        displayName: '${_profile?.displayName ?? "User"} (updated)',
        preferences: {
          'theme': 'dark',
          'notifications': true,
          'updated_at': DateTime.now().toIso8601String(),
        },
      );

      setState(() {
        _profile = updatedProfile;
        _statusMessage = 'Profile updated';
      });
    } on CertificatePinningException {
      _showMessage('Security error: Connection could not be verified.');
    } on ApiException catch (e) {
      _showMessage('Failed to update profile: ${e.message}');
    } catch (e) {
      _showMessage('Error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _performSync() async {
    if (_services.syncService.isSyncing) {
      _showMessage('Sync already in progress');
      return;
    }

    setState(() => _isLoading = true);

    try {
      // Example local changes to push
      final localChanges = [
        SyncItem(
          id: 'item-1',
          type: 'note',
          data: {
            'title': 'Sample Note',
            'content': 'Synced from mobile',
          },
          modifiedAt: DateTime.now(),
          action: 'update',
        ),
      ];

      final result = await _services.syncService.sync(
        localChanges: localChanges,
      );

      setState(() {
        _lastSyncResult = result;
        _statusMessage = result.success
            ? 'Sync completed: ${result.itemsPushed} pushed, ${result.itemsPulled} pulled'
            : 'Sync completed with ${result.conflicts.length} conflicts';
      });
    } on CertificatePinningException {
      _showMessage('Security error: Connection could not be verified.');
    } on ApiException catch (e) {
      _showMessage('Sync failed: ${e.message}');
    } on StateError catch (e) {
      _showMessage(e.message);
    } catch (e) {
      _showMessage('Sync error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  Future<void> _pullChanges() async {
    setState(() => _isLoading = true);

    try {
      final changes = await _services.syncService.pullChanges();

      setState(() {
        _statusMessage = 'Pulled ${changes.length} changes';
      });
    } on CertificatePinningException {
      _showMessage('Security error: Connection could not be verified.');
    } on ApiException catch (e) {
      _showMessage('Pull failed: ${e.message}');
    } catch (e) {
      _showMessage('Error: $e');
    } finally {
      setState(() => _isLoading = false);
    }
  }

  void _showMessage(String message) {
    setState(() => _statusMessage = message);
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text(message), duration: const Duration(seconds: 3)),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('API Client Demo'),
        backgroundColor: Theme.of(context).colorScheme.inversePrimary,
        actions: [
          if (_isAuthenticated)
            IconButton(
              icon: const Icon(Icons.logout),
              onPressed: _isLoading ? null : _logout,
            ),
        ],
      ),
      body: _isLoading
          ? const Center(child: CircularProgressIndicator())
          : SingleChildScrollView(
              padding: const EdgeInsets.all(16),
              child: _isAuthenticated
                  ? _buildAuthenticatedView()
                  : _buildLoginView(),
            ),
    );
  }

  Widget _buildLoginView() {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        const Icon(Icons.lock_outline, size: 64, color: Colors.blue),
        const SizedBox(height: 24),
        TextField(
          controller: _emailController,
          decoration: const InputDecoration(
            labelText: 'Email',
            border: OutlineInputBorder(),
            prefixIcon: Icon(Icons.email),
          ),
          keyboardType: TextInputType.emailAddress,
          autocorrect: false,
        ),
        const SizedBox(height: 16),
        TextField(
          controller: _passwordController,
          decoration: const InputDecoration(
            labelText: 'Password',
            border: OutlineInputBorder(),
            prefixIcon: Icon(Icons.lock),
          ),
          obscureText: true,
        ),
        const SizedBox(height: 24),
        FilledButton(
          onPressed: _login,
          child: const Text('Login'),
        ),
        const SizedBox(height: 12),
        OutlinedButton(
          onPressed: _register,
          child: const Text('Register'),
        ),
        if (_statusMessage != null) ...[
          const SizedBox(height: 16),
          Text(
            _statusMessage!,
            style: TextStyle(
              color: _statusMessage!.contains('error') ||
                      _statusMessage!.contains('failed')
                  ? Colors.red
                  : Colors.green,
            ),
            textAlign: TextAlign.center,
          ),
        ],
      ],
    );
  }

  Widget _buildAuthenticatedView() {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // Profile Card
        Card(
          child: Padding(
            padding: const EdgeInsets.all(16),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  children: [
                    CircleAvatar(
                      radius: 30,
                      child: Text(
                        _profile?.displayName.substring(0, 1).toUpperCase() ??
                            '?',
                        style: const TextStyle(fontSize: 24),
                      ),
                    ),
                    const SizedBox(width: 16),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            _profile?.displayName ?? 'Loading...',
                            style: Theme.of(context).textTheme.titleLarge,
                          ),
                          Text(
                            _profile?.email ?? '',
                            style: Theme.of(context).textTheme.bodyMedium,
                          ),
                        ],
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 16),
                Row(
                  children: [
                    Expanded(
                      child: OutlinedButton.icon(
                        onPressed: _loadProfile,
                        icon: const Icon(Icons.refresh),
                        label: const Text('Refresh'),
                      ),
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: FilledButton.icon(
                        onPressed: _updateProfile,
                        icon: const Icon(Icons.edit),
                        label: const Text('Update'),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
        const SizedBox(height: 16),

        // Sync Card
        Card(
          child: Padding(
            padding: const EdgeInsets.all(16),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'Data Synchronization',
                  style: Theme.of(context).textTheme.titleMedium,
                ),
                const SizedBox(height: 8),
                if (_services.syncService.lastSyncTime != null)
                  Text(
                    'Last sync: ${_services.syncService.lastSyncTime}',
                    style: Theme.of(context).textTheme.bodySmall,
                  ),
                if (_lastSyncResult != null) ...[
                  const SizedBox(height: 4),
                  Text(
                    'Pushed: ${_lastSyncResult!.itemsPushed}, Pulled: ${_lastSyncResult!.itemsPulled}',
                    style: Theme.of(context).textTheme.bodySmall,
                  ),
                  if (_lastSyncResult!.conflicts.isNotEmpty)
                    Text(
                      'Conflicts: ${_lastSyncResult!.conflicts.length}',
                      style: Theme.of(context).textTheme.bodySmall?.copyWith(
                            color: Colors.orange,
                          ),
                    ),
                ],
                const SizedBox(height: 16),
                Row(
                  children: [
                    Expanded(
                      child: FilledButton.icon(
                        onPressed: _performSync,
                        icon: const Icon(Icons.sync),
                        label: const Text('Full Sync'),
                      ),
                    ),
                    const SizedBox(width: 8),
                    Expanded(
                      child: OutlinedButton.icon(
                        onPressed: _pullChanges,
                        icon: const Icon(Icons.cloud_download),
                        label: const Text('Pull'),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),

        if (_statusMessage != null) ...[
          const SizedBox(height: 16),
          Card(
            color: _statusMessage!.contains('error') ||
                    _statusMessage!.contains('failed') ||
                    _statusMessage!.contains('Security')
                ? Colors.red.shade50
                : Colors.green.shade50,
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Text(
                _statusMessage!,
                textAlign: TextAlign.center,
                style: TextStyle(
                  color: _statusMessage!.contains('error') ||
                          _statusMessage!.contains('failed') ||
                          _statusMessage!.contains('Security')
                      ? Colors.red.shade700
                      : Colors.green.shade700,
                ),
              ),
            ),
          ),
        ],
      ],
    );
  }
}